// AuditEntry One row of the audit query result.
//
// Field-to-column mapping (see module docstring for the substrate
// reconciliation):
//
//   - “id“ ← “audit_log.id“
//   - “ts“ ← “audit_log.occurred_at“
//   - “tenant_id“ ← “audit_log.tenant_id“
//   - “principal_sub“ ← “audit_log.operator_sub“
//   - “target_id“ ← “audit_log.target_id“
//   - “target_name“ ← LEFT JOIN “targets.name“ ON “audit_log.target_id“
//   - “method“ / “path“ / “status_code“ / “request_id“ / “duration_ms“
//     / “payload“ ← columns of the same name
//   - “op_id“ / “op_class“ / “result_status“ — computed at query time
//   - “parent_audit_id“ ← “audit_log.parent_audit_id“ (lineage; #398)
//   - “agent_session_id“ ← “audit_log.agent_session_id“ (MCP session; #1009)
//   - “principal_name“ ← “payload['principal_name']“ when set. The MCP
//     audit-write helper (“write_mcp_audit_row“) populates it from
//     “Operator.name“ since G0.15-T3 #1212; HTTP-chassis rows remain
//     None pending a separate fix to bind “name“ to contextvars in
//     “verify_jwt_and_bind“.
//   - “broadcast_event_id“ — v0.2 placeholder, always None (FK direction
//     is reversed: “BroadcastEvent.audit_id“ points at the audit row).
type AuditEntry struct {
	AgentSessionId   *openapi_types.UUID    `json:"agent_session_id"`
	BroadcastEventId *openapi_types.UUID    `json:"broadcast_event_id"`
	DurationMs       *string                `json:"duration_ms"`
	Id               openapi_types.UUID     `json:"id"`
	Method           string                 `json:"method"`
	OpClass          string                 `json:"op_class"`
	OpId             string                 `json:"op_id"`
	ParentAuditId    *openapi_types.UUID    `json:"parent_audit_id"`
	Path             string                 `json:"path"`
	Payload          map[string]interface{} `json:"payload"`
	PrincipalName    *string                `json:"principal_name"`
	PrincipalSub     string                 `json:"principal_sub"`
	RequestId        *openapi_types.UUID    `json:"request_id"`
	ResultStatus     string                 `json:"result_status"`
	StatusCode       int                    `json:"status_code"`
	TargetId         *openapi_types.UUID    `json:"target_id"`
	TargetName       *string                `json:"target_name"`
	TenantId         *openapi_types.UUID    `json:"tenant_id"`
	Ts               time.Time              `json:"ts"`
}

// AuditQueryRequest POST body for “/api/v1/audit/query“.
//
// Mirrors :class:`~meho_backplane.audit_query.AuditQueryFilters`
// except “since“ / “until“ are strings parsed by
// :func:`~meho_backplane.audit_query.parse_duration` at the router
// layer. All other fields pass through to the substrate filter
// object unchanged. The empty body shape “{}“ is the no-filter
// case — every field defaults to None or the substrate-side default.
//
// “extra="forbid"“ rejects unknown fields with 422
// “extra_forbidden“ so a typo or a client passing “tenant_id“
// in the body fails loud at the framework boundary — the route
// always uses “operator.tenant_id“ from the JWT, never the body.
type AuditQueryRequest struct {
	AgentSessionId *openapi_types.UUID `json:"agent_session_id"`
	AuditId        *openapi_types.UUID `json:"audit_id"`
	Cursor         *string             `json:"cursor"`
	Limit          *int                `json:"limit,omitempty"`
	OpClass        *string             `json:"op_class"`
	OpId           *string             `json:"op_id"`
	ParentAuditId  *openapi_types.UUID `json:"parent_audit_id"`
	Principal      *string             `json:"principal"`
	ResultStatus   *string             `json:"result_status"`
	Since          *string             `json:"since"`
	Target         *string             `json:"target"`
	Until          *string             `json:"until"`
}

// AuditQueryResult Page of audit rows plus the forward-only continuation cursor.
//
// “next_cursor“ is :data:`None` when fewer than “limit“ rows were
// available (the query reached the end of the matching set). Consumers
// iterate by re-issuing the same filter with “cursor = next_cursor“
// until “next_cursor“ is None.
type AuditQueryResult struct {
	NextCursor *string      `json:"next_cursor"`
	Rows       []AuditEntry `json:"rows"`
}

// AuditReplayResult 200 body for “GET /api/v1/audit/sessions/{session_id}/replay“.
//
// Wraps the substrate's :class:`ReplayNode` forest with the echoed
// request identity. “tenant_id“ is always the operator's tenant
// (lifted from the JWT by the route), never client-supplied, so the
// echo is a confirmation of the boundary the query ran under — not a
// value the caller chose.
//
// “row_count“ is the count of *anchor* rows in the session — rows
// whose “agent_session_id“ equals “session_id“ within the
// operator's tenant. It is the same number the route's count-first
// 413 guard evaluates, so a session that returns 200 reports a
// “row_count“ identical to what its over-cap sibling would report
// at 413. NULL-session lineage children pulled into “root“ by the
// replay closure (a composite “dispatch_child“ whose own
// “agent_session_id“ is NULL but whose “parent_audit_id“ links
// into the session) are present in the tree but are not counted —
// "session rows" are defined by the “agent_session_id“ anchor, not
// by tree membership.
//
// An unknown session id, or one belonging to another tenant, yields
// “root=[]“ / “row_count=0“ — never a 404 — so a foreign session
// is indistinguishable from an empty one and existence never leaks
// across tenants (the same non-leakage posture
// “GET /show/{audit_id}“ takes).
//
// Frozen like the substrate models it carries.
type AuditReplayResult struct {
	Root      []ReplayNode       `json:"root"`
	RowCount  int                `json:"row_count"`
	SessionId openapi_types.UUID `json:"session_id"`
	TenantId  openapi_types.UUID `json:"tenant_id"`
}

// AuthConfigResponse OAuth discovery surface returned to “meho login“.
//
// Field names match the CLI's expected JSON keys (“keycloak_issuer“,
// “audience“, “cli_client_id“); renaming any field is a wire-compat
// break for the CLI's discovery parser. “cli_client_id“ defaults to
// the empty string on the response when the backplane has not been
// wired (“KEYCLOAK_CLI_CLIENT_ID“ unset); the CLI distinguishes
// empty-string from absent-key and emits the same actionable
// public-client error in both cases.
type AuthConfigResponse struct {
	Audience       string `json:"audience"`
	CliClientId    string `json:"cli_client_id"`
	KeycloakIssuer string `json:"keycloak_issuer"`
}

